// 同步复位 D 触发器 (Synchronous Reset D Flip-Flop)
// 设计说明：
// 1. 复位信号 (rst_n) 仅在时钟上升沿被采样。
// 2. 即使 rst_n 为低电平，如果 clk 没有上升沿，输出 q 也不会改变。
// 3. 这种结构避免了异步复位带来的亚稳态传播风险，但要求复位信号必须满足建立时间 (setup time)。

module dff_sync_reset (
    input  wire clk,      // 系统时钟
    input  wire rst_n,    // 同步低电平复位信号 (Active Low)
    input  wire d,        // 数据输入
    output reg  q         // 数据输出
);

    always @(posedge clk) begin
        if (!rst_n) begin
            // 在时钟上升沿检测到复位信号有效时，将输出清零
            q <= 1'b0; 
        end else begin
            // 否则，将输入数据 d 锁存到输出 q
            q <= d;
        end
    end

endmodule
