// 4-bit Ripple Carry Adder (RCA)
// 功能：实现两个4位无符号数的加法，并输出和与进位
// 设计思路：采用行波进位结构，由4个全加器级联而成
// 可综合，适用于ASIC/FPGA逻辑综合

module adder_4bit (
    input  wire [3:0] a,      // 4位操作数A
    input  wire [3:0] b,      // 4位操作数B
    input  wire       cin,    // 低位进位输入
    output wire [3:0] sum,    // 4位和输出
    output wire       cout    // 高位进位输出
);

    // 内部信号定义：用于连接各级全加器的进位链
    wire c1; // 第0位到第1位的进位
    wire c2; // 第1位到第2位的进位
    wire c3; // 第2位到第3位的进位

    // 实例化4个全加器 (Full Adder)，构成行波进位加法器
    // FA_0: 处理最低有效位 (LSB, bit 0)
    full_adder fa_0 (
        .a   (a[0]),
        .b   (b[0]),
        .cin (cin),
        .sum (sum[0]),
        .cout(c1)
    );

    // FA_1: 处理第1位，接收来自FA_0的进位c1
    full_adder fa_1 (
        .a   (a[1]),
        .b   (b[1]),
        .cin (c1),
        .sum (sum[1]),
        .cout(c2)
    );

    // FA_2: 处理第2位，接收来自FA_1的进位c2
    full_adder fa_2 (
        .a   (a[2]),
        .b   (b[2]),
        .cin (c2),
        .sum (sum[2]),
        .cout(c3)
    );

    // FA_3: 处理最高有效位 (MSB, bit 3)，接收来自FA_2的进位c3
    full_adder fa_3 (
        .a   (a[3]),
        .b   (b[3]),
        .cin (c3),
        .sum (sum[3]),
        .cout(cout)
    );

endmodule

// ------------------------------------------------------------------
// 子模块：全加器 (Full Adder)
// 逻辑方程：Sum = A ^ B ^ Cin
//           Cout = (A & B) | (Cin & (A ^ B))
// ------------------------------------------------------------------
module full_adder (
    input  wire a,
    input  wire b,
    input  wire cin,
    output wire sum,
    output wire cout
);

    assign sum  = a ^ b ^ cin;
    // 优化后的进位逻辑：先计算异或，再与进位输入相与，最后与AB相或
    assign cout = (a & b) | (cin & (a ^ b));

endmodule
